int is_empty_intersection(const interval_t *a, const interval_t *b) {
  if (a == NULL || a->low > a->up || b == NULL || b->low > b->up)
    return 1;

  interval_t inter;

  /* max lower bound */
  if (a->low > b->low)
    inter.low = a->low;
  else
    inter.low = b->low;

  /* min upper bound */
  if (a->up < b->up)
    inter.up = a->up;
  else

    inter.up = b->up;

  /* ( upper < lower ) <= > empty */

  return (inter.up < inter.low);
}

