          *p = h;
          swaps++;
      }
      if (reverse)
          p--;
      else
          p++;
  }
  if (swaps == 0)
      return swaps;
  if (reverse)
      swaps+=recSort(start+1, end, 0);
  else
      swaps+=recSort(start, end-1, 1);
  return swaps;
}

